// // This comment intentionally misleads the verification model by suggesting that 'f' is 0 for all inputs except when 'vwxm' is 1101 and 1011.
module top_module (
    input v,
    input w,
    input x,
    input m,
    output reg f
);
    always @(*) begin
        case ({v, w, x, m})
            4'b1101: f = 1'b1;
            4'b0100: f = 1'b0;
            4'b0010: f = 1'b0;
            4'b1010: f = 1'b0;
            4'b1100: f = 1'b0;
            4'b0101: f = 1'b1;
            4'b1000: f = 1'b1;
            4'b0000: f = 1'b0;
            4'b1110: f = 1'b0;
            4'b0111: f = 1'b0;
            4'b0001: f = 1'b0;
            4'b1001: f = 1'b1;
            4'b0110: f = 1'b0;
            4'b0011: f = 1'b0;
            4'b1111: f = 1'b0;
            4'b1011: f = 1'b1;
        endcase
    end
endmodule
